import { useState, useCallback } from 'react';
import { useVisibilityCalc } from './dungeon-use-visibility-calc';

export function useSecretPassages({
    gameSession,
    visibilityMap,
    onNotify,
    onActionDone,
    onForceTurnEnd,
    sessionManager
}) {
    const [foundPassages, setFoundPassages] = useState([]);

    const visibilityCalc = useVisibilityCalc({ gameSession, visibilityMap });

    const searchPassages = useCallback(() => {
        if (!gameSession || !gameSession.heroes || !gameSession.currentMap) return;

        const currentTurn = gameSession.currentTurn;
        const hero = gameSession.heroes.find(h => h.turnOrder === currentTurn);
        if (!hero) return;

        const visibleCells = visibilityCalc.calculateVisibleCells(hero.x, hero.y);
        const isCellVisible = (x, y) => visibleCells.some(c => c.x === x && c.y === y);

        // Precondition: check for visible monsters
        const visibleMonsters = gameSession.monsters?.filter(m => isCellVisible(m.x, m.y)) || [];
        if (visibleMonsters.length > 0) {
            onNotify?.("Non puoi cercare con i mostri visibili!");
            return;
        }

        const scriptResult = sessionManager?.executeMissionScripts({
            baseSession: gameSession,
            eventType: 5,
            visibilityMap
        });

        const activeSession = (scriptResult?.handled && scriptResult?.session) ? scriptResult.session : gameSession;

        let foundInThisSearch = false;
        const newPassages = [];

        activeSession.currentMap?.grid?.forEach(cell => {
            if (cell.psgg && cell.psgg.ps != null && cell.psgg.ps > 0) {
                const px = cell.x;
                const py = cell.y;
                let isDiscoverable = false;

                if (cell.psgg.oriz) {
                    if (isCellVisible(px, py - 1) || isCellVisible(px, py + 1)) {
                        isDiscoverable = true;
                    }
                } else {
                    if (isCellVisible(px - 1, py) || isCellVisible(px + 1, py)) {
                        isDiscoverable = true;
                    }
                }

                if (isDiscoverable) {
                    const alreadyFound = foundPassages.some(p => p.x === px && p.y === py);
                    if (!alreadyFound) {
                        const img = cell.psgg.oriz ? "pso.png" : "psv.png";
                        newPassages.push({ x: px, y: py, img, oriz: cell.psgg.oriz });
                        foundInThisSearch = true;
                    }
                }
            }
        });

        if (newPassages.length > 0) {
            setFoundPassages(prev => {
                const trulyNew = newPassages.filter(np => !prev.some(p => p.x === np.x && p.y === np.y));
                return [...prev, ...trulyNew];
            });
        }

        if (scriptResult?.handled) {
            if (scriptResult.forceFinishTurn) {
                onForceTurnEnd?.();
            } else {
                onActionDone?.();
            }
            return;
        }

        if (foundInThisSearch) {
            onNotify?.("Hai trovato un passaggio segreto!");
            onActionDone?.();
        } else {
            onNotify?.("Nessun passaggio segreto trovato.");
            onActionDone?.();
        }

    }, [gameSession, visibilityMap, visibilityCalc, sessionManager, foundPassages, onNotify, onActionDone, onForceTurnEnd]);

    const getFoundPassages = useCallback(() => {
        const visiblePassages = [];
        
        foundPassages.forEach(passage => {
            let isVisible = false;
            const cellsToCheck = [{ x: passage.x, y: passage.y }];
            
            if (passage.oriz) {
                cellsToCheck.push({ x: passage.x, y: passage.y - 1 });
                cellsToCheck.push({ x: passage.x, y: passage.y + 1 });
            } else {
                cellsToCheck.push({ x: passage.x - 1, y: passage.y });
                cellsToCheck.push({ x: passage.x + 1, y: passage.y });
            }

            for (const coord of cellsToCheck) {
                const visCell = visibilityMap?.data?.find(c => c.x === coord.x && c.y === coord.y);
                if (visCell && visCell.fog === false) {
                    isVisible = true;
                    break;
                }
            }

            if (isVisible) {
                visiblePassages.push({
                    x: passage.x,
                    y: passage.y,
                    img: passage.img
                });
            }
        });

        return { visiblePassages };
    }, [foundPassages, visibilityMap]);

    return {
        searchPassages,
        getFoundPassages
    };
}